// Aggregate and parse all content sources into a unified trending topics list
const allInputs = $input.all();
const allTopics = [];

const categories = ['google_trends', 'ai_tech', 'digital_marketing', 'web_development', 'corporate_gifting'];
const categoryLabels = {
  'google_trends': 'General Trends',
  'ai_tech': 'AI & Technology',
  'digital_marketing': 'Digital Marketing',
  'web_development': 'Web Development',
  'corporate_gifting': 'Corporate Gifting'
};

for (let i = 0; i < allInputs.length; i++) {
  const rawData = allInputs[i].json.data || allInputs[i].json.body || '';
  let text = typeof rawData === 'string' ? rawData : JSON.stringify(rawData);
  const category = categories[i] || 'general';

  if (category === 'google_trends') {
    // Parse Google Trends JSON
    if (text.startsWith(')]}')) text = text.substring(5);
    try {
      const parsed = JSON.parse(text);
      const days = parsed?.default?.trendingSearchesDays || [];
      for (const day of days) {
        for (const trend of (day.trendingSearches || []).slice(0, 3)) {
          allTopics.push({
            title: trend.title?.query || '',
            snippet: trend.articles?.[0]?.snippet || '',
            source: trend.articles?.[0]?.source || 'Google Trends',
            category: categoryLabels[category],
            traffic: trend.formattedTraffic || ''
          });
        }
      }
    } catch(e) {}
  } else {
    // Parse RSS XML from Google News
    const itemRegex = /<item>([\s\S]*?)<\/item>/g;
    let match;
    let count = 0;
    while ((match = itemRegex.exec(text)) !== null && count < 3) {
      const itemXml = match[1];
      const titleMatch = itemXml.match(/<title><!\[CDATA\[(.+?)\]\]><\/title>/) || itemXml.match(/<title>(.+?)<\/title>/);
      const descMatch = itemXml.match(/<description><!\[CDATA\[(.+?)\]\]><\/description>/) || itemXml.match(/<description>(.+?)<\/description>/);
      const sourceMatch = itemXml.match(/<source[^>]*>(.+?)<\/source>/);
      const pubDateMatch = itemXml.match(/<pubDate>(.+?)<\/pubDate>/);

      if (titleMatch) {
        allTopics.push({
          title: titleMatch[1].replace(/<[^>]+>/g, '').trim(),
          snippet: descMatch ? descMatch[1].replace(/<[^>]+>/g, '').trim().substring(0, 200) : '',
          source: sourceMatch ? sourceMatch[1] : 'Google News',
          category: categoryLabels[category],
          pubDate: pubDateMatch ? pubDateMatch[1] : ''
        });
        count++;
      }
    }
  }
}

return [{
  json: {
    trends: allTopics.slice(0, 15),
    categories_covered: Object.values(categoryLabels),
    fetchedAt: new Date().toISOString()
  }
}];

